const items = $input.all();

return items.map(item => ({
  json: {
    "Candidate ID": item.json.candidate_name_hexed || "",
    "Executive Summary": item.json.executive_summary || "",
    "Contact Phone": item.json.contact_phone || "",
    "Key Strengths": item.json.key_strengths || "",
    "Missing Qualifications": item.json.missing_qualifications || "",
    "Match Percentage": item.json.match_score || 0,
    "Recommendation": item.json.recommendation || ""
  }
}));

parameters.functionCode:
return items.map(item => {
  // Specify the exact binary property name you want to extract
  const targetKey = 'cv_post_file'; 

  // Check if this binary property exists in the current item
  if (item.binary && item.binary[targetKey]) {
    const fileData = item.binary[targetKey];
    const fileName = fileData.fileName;
    const extension = fileName.split('.').pop().toLowerCase();

    return {
      json: {
        filename: fileName,
        fileExtension: extension,
      },
      binary: {
        // We output it as 'data' so downstream nodes can easily process it
        cv_data: fileData, 
      },
    };
  }

  // If the file isn't found, return the item as is (or return null to drop it)
  return item; 
});


